import React, { useEffect, useRef, useState } from 'react';
import './App.css';

interface Result {
  id: number;
  name: string;
  email: string;
}

type SearchStatus = 'idle' | 'loading' | 'success' | 'empty' | 'error';

const FAKE_DATA: Result[] = [
  { id: 1, name: 'Alice Johnson', email: 'alice@example.com' },
  { id: 2, name: 'Bob Smith', email: 'bob@example.com' },
  { id: 3, name: 'Charlie Kim', email: 'charlie@example.com' },
  { id: 4, name: 'Diana Lopez', email: 'diana@example.com' },
  { id: 5, name: 'Ethan Brown', email: 'ethan@example.com' },
  { id: 6, name: 'Fiona Patel', email: 'fiona@example.com' }
];

function abortError(): DOMException {
  return new DOMException('Search aborted', 'AbortError');
}

function fakeApiSearch(term: string, signal: AbortSignal): Promise<Result[]> {
  const normalized = term.trim().toLowerCase();

  return new Promise((resolve, reject) => {
    let settled = false;
    const timeoutId = window.setTimeout(() => {
      if (settled) return;
      settled = true;
      signal.removeEventListener('abort', onAbort);

      if (normalized === 'error') {
        reject(new Error('Fake API error'));
        return;
      }

      resolve(FAKE_DATA.filter((item) => {
        const name = item.name.toLowerCase();
        const email = item.email.toLowerCase();
        return name.includes(normalized) || email.includes(normalized);
      }));
    }, 600);

    const onAbort = () => {
      if (settled) return;
      settled = true;
      window.clearTimeout(timeoutId);
      signal.removeEventListener('abort', onAbort);
      reject(abortError());
    };

    signal.addEventListener('abort', onAbort, { once: true });
    if (signal.aborted) onAbort();
  });
}

export default function App() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Result[]>([]);
  const [status, setStatus] = useState<SearchStatus>('idle');
  const [error, setError] = useState<string | null>(null);
  const requestGeneration = useRef(0);
  const isLoading = status === 'loading';

  useEffect(() => {
    const generation = ++requestGeneration.current;
    const normalized = query.trim();

    if (!normalized) {
      setResults([]);
      setError(null);
      setStatus('idle');
      return;
    }

    const controller = new AbortController();
    setResults([]);
    setError(null);
    setStatus('loading');

    const debounceId = window.setTimeout(() => {
      fakeApiSearch(normalized, controller.signal)
        .then((data) => {
          if (controller.signal.aborted || requestGeneration.current !== generation) return;
          setResults(data);
          setError(null);
          setStatus(data.length ? 'success' : 'empty');
        })
        .catch((reason: unknown) => {
          if (controller.signal.aborted || requestGeneration.current !== generation) return;
          setResults([]);
          setError(reason instanceof Error ? reason.message : 'Something went wrong.');
          setStatus('error');
        });
    }, 500);

    return () => {
      window.clearTimeout(debounceId);
      controller.abort();
    };
  }, [query]);

  const onInput = (event: React.ChangeEvent<HTMLInputElement>) => {
    const value = event.target.value;
    requestGeneration.current += 1;
    setQuery(value);
    setResults([]);
    setError(null);
    setStatus(value.trim() ? 'loading' : 'idle');
  };

  return (
    <main className="main">
      <section className="card">
        <header className="header">
          <h1 className="title">Debounced Search</h1>
          <p className="subtitle">Type to search a fake user directory. Search runs 500ms after you stop typing.</p>
        </header>

        <div className="field">
          <label className="label" htmlFor="search-input">Search</label>
          <input
            id="search-input"
            className="input"
            type="text"
            value={query}
            onChange={onInput}
            placeholder="Start typing a name or email..."
            autoComplete="off"
            aria-describedby="search-status"
            aria-controls="search-results"
          />
        </div>

        <div
          id="search-status"
          className="status-row"
          role="status"
          aria-live="polite"
          aria-atomic="true"
        >
          {status === 'loading' && <span className="status status--loading">Searching…</span>}
          {status === 'success' && (
            <span className="status">Showing {results.length} result(s) for "{query}"</span>
          )}
          {status === 'idle' && (
            <span className="status status--muted">Start typing to search.</span>
          )}
          {status === 'error' && (
            <span className="status status--error" role="alert">{error}</span>
          )}
        </div>

        <div id="search-results" className="results-region" aria-busy={isLoading}>
          {status === 'success' && (
            <ul className="results" aria-label="Search results">
              {results.map((result) => (
                <li key={result.id} className="result-row">
                  <div className="result-name">{result.name}</div>
                  <div className="result-email">{result.email}</div>
                </li>
              ))}
            </ul>
          )}
          {status === 'empty' && (
            <p className="empty">No results found for "{query}".</p>
          )}
        </div>
      </section>
    </main>
  );
}

