:root { color-scheme: dark; }
html, body { margin: 0; height: 100%; background:#020617; font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif; }

.main { min-height:100vh; background:#020617; color:#e5e7eb; display:grid; place-items:center; padding:24px; }
.card { width:100%; max-width:640px; background:#020617; border-radius:16px; border:1px solid #1f2937; padding:18px 18px 16px; display:grid; gap:16px; }
.header { display:grid; gap:4px; }
.title { margin:0; font-size:20px; font-weight:700; }
.subtitle { margin:0; font-size:13px; color:#9ca3af; }
.field { display:grid; gap:6px; }
.label { font-size:13px; color:#9ca3af; }
.input { width:100%; border-radius:999px; border:1px solid #374151; background:#020617; color:#e5e7eb; padding:8px 12px; font-size:14px; outline:none; }
.input:focus { border-color:#a3e635; box-shadow:0 0 0 1px #a3e63533; }
.status-row { min-height:18px; font-size:12px; display:flex; align-items:center; }
.status { color:#9ca3af; }
.status--loading { color:#e5e7eb; }
.status--muted { color:#6b7280; }
.status--error { color:#f97316; }
.results-region { min-height:1px; }
.results { list-style:none; margin:0; padding:0; display:grid; gap:8px; }
.result-row { padding:8px 10px; border-radius:10px; border:1px solid #1f2937; background:#020617; display:grid; gap:2px; }
.result-name { font-size:14px; font-weight:600; }
.result-email { font-size:12px; color:#9ca3af; font-variant-numeric:tabular-nums; }
.empty { margin:0; font-size:13px; color:#6b7280; }
